    """
    Look up the cached user anime list and return a set of anime IDs
    that the user has already watched (status != PLANNING).

    Tries exact match first, then lowercased-without-hyphens (to handle
    username normalization differences between fetch and recommendation flows).

    Returns an empty set if no cache is found.
    """
    cache_keys = [
        f"{source}_user_{username}",
        f"{source}_user_{username.lower().replace('-', '')}",
    ]
    # Also try the reversed: if user typed without hyphen, try with hyphen
    if '-' in username:
        cache_keys.append(f"{source}_user_{username.lower()}")
    elif username != username.lower():
        cache_keys.append(f"{source}_user_{username.lower()}")

    for ck in cache_keys:
        cached = _load_cache(ck, max_age_secs=3600)
        if cached:
            break
    else:
        return set()

    anime_list = cached.get("animeList", [])
    watched_ids = set()
    for ua in anime_list:
